const b = $input.first().json.body || $input.first().json;
const amount = Number(b.firstOrderAmount || 0);
const payout = Math.round(amount * 0.15 * 100) / 100;
const usd = (n) => new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', maximumFractionDigits: 0 }).format(n);
return [{ json: { ...b, amountFormatted: usd(amount), payoutFormatted: usd(payout) } }];
